### code section 1 (python)
def entropy_bound_mask(entropies, bound):
    accepted = [False] * len(entropies)
    cumulative = 0.0
    for index in sorted(range(len(entropies)), key=entropies.__getitem__):
        cumulative += entropies[index]
        if cumulative - entropies[index] <= bound:
            accepted[index] = True
    return tuple(accepted)

### code section 2 (typescript)
export async function retryWithBackoff<T>(fn: () => Promise<T>, retries = 5): Promise<T> {
  let delay = 100;
  for (let attempt = 0; ; attempt++) {
    try { return await fn(); } catch (error) {
      if (attempt >= retries) throw error;
      await new Promise(r => setTimeout(r, delay));
      delay = Math.min(delay * 2, 5000);
    }
  }
}

### code section 3 (rust)
fn softmax(logits: &[f32]) -> Vec<f32> {
    let max = logits.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
    let exps: Vec<f32> = logits.iter().map(|x| (x - max).exp()).collect();
    let sum: f32 = exps.iter().sum();
    exps.iter().map(|x| x / sum).collect()
}

